```typescript
async function validateTagIds(ids: string[]): Promise<void> {
  if (!ids.length) return;
  const found = await db.query('SELECT id FROM tags WHERE id = ANY($1)', [ids]);
  const foundIds = new Set(found.rows.map((r: any) => r.id));
  const missing = ids.filter(id => !foundIds.has(id));
  if (missing.length) {
    throw new NotFoundError(`Tags not found: ${missing.join(', ')}`);
  }
}
