  const row = await db.query('SELECT * FROM users WHERE id = $1', [id]);
  if (!row.rows.length) throw new NotFoundError('User not found');
  if (row.rows[0].user_id !== userId && !row.rows[0].is_public) throw new ForbiddenError('Forbidden');
