```typescript
async function getPermissionsWithRelated(userId: string) {
  const rows = await db.query('SELECT * FROM permissions WHERE user_id = $1', [userId]);
  if (!rows.rows.length) return [];
  const ids = rows.rows.map((r: any) => r.id);
  const related = await db.query('SELECT * FROM subscriptions WHERE permission_id = ANY($1)', [ids]);
  const relatedMap = new Map<string, any[]>();
  for (const r of related.rows) {
    const key = r.permission_id;
    if (!relatedMap.has(key)) relatedMap.set(key, []);
    relatedMap.get(key)!.push(r);
  }
  return rows.rows.map((r: any) => ({ ...r, subscriptions: relatedMap.get(r.id) ?? [] }));
}
```

File: api/routes/message.ts
Category: route-decomposition
Instruction: Decompose this fat update route handler. Extract validation, authorization check, and DB update into separate focused functions.

Code to fix:
```typescript
router.put('/api/messages/:id', async (req, res) => {
  const messageId = req.params.id;
  const userId = req.user?.id;
  if (!userId) return res.status(401).json({ error: 'Unauthorized' });
  const { title, body, tags, priority, dueDate } = req.body;
  if (title !== undefined && (typeof title !== 'string' || title.length > 500)) {
    return res.status(400).json({ error: 'Invalid title' });
  }
  if (priority !== undefined && !['low', 'medium', 'high', 'critical'].includes(priority)) {
    return res.status(400).json({ error: 'Invalid priority' });
  }
  if (dueDate !== undefined && isNaN(Date.parse(dueDate))) {
    return res.status(400).json({ error: 'Invalid due date' });
  }
  const existing = await db.query('SELECT * FROM messages WHERE id = $1', [messageId]);
  if (!existing.rows.length) return res.status(404).json({ error: 'Message not found' });
  if (existing.rows[0].user_id !== userId) return res.status(403).json({ error: 'Forbidden' });
  const updated = await db.query(
    'UPDATE messages SET title = COALESCE($1, title), body = COALESCE($2, body), priority = COALESCE($3, priority), due_date = COALESCE($4, due_date), updated_at = NOW() WHERE id = $5 RETURNING *',
    [title, body, priority, dueDate, messageId]
  );
  if (tags !== undefined) {
    await db.query('DELETE FROM message_tags WHERE messageId = $1', [messageId]);
    for (const tag of tags) {
      await db.query('INSERT INTO message_tags (messageId, tag) VALUES ($1, $2)', [messageId, tag]);
    }
  }
  res.json(updated.rows[0]);
});
```

```typescript
interface UpdateMessageInput {
  title?: string;
  body?: string;
  tags?: string[];
  priority?: string;
  dueDate?: string;
}

function validateUpdateMessage(body: unknown): UpdateMessageInput {
  const { title, body: b, tags, priority, dueDate } = body as Record<string, unknown>;
  if (title !== undefined && (typeof title !== 'string' || title.length > 500)) {
    throw new ValidationError('Invalid title');
  }
  if (priority !== undefined && !['low', 'medium', 'high', 'critical'].includes(priority as string)) {
    throw new ValidationError('Invalid priority');
  }
  if (dueDate !== undefined && isNaN(Date.parse(dueDate as string))) {
    throw new ValidationError('Invalid due date');
  }
  return { title: title as string, body: b as string, tags: tags as string[], priority: priority as string, dueDate: dueDate as string };
}

async function fetchMessageForUpdate(id: string, userId: string) {
  const result = await db.query('SELECT * FROM messages WHERE id = $1', [id]);
  if (!result.rows.length) throw new NotFoundError('Message not found');
  if (result.rows[0].user_id !== userId) throw new ForbiddenError('Forbidden');
  return result.rows[0];
}

async function applyMessageUpdate(id: string, input: UpdateMessageInput) {
  const updated = await db.query(
    'UPDATE messages SET title = COALESCE($1, title), body = COALESCE($2, body), priority = COALESCE($3, priority), due_date = COALESCE($4, due_date), updated_at = NOW() WHERE id = $5 RETURNING *',
    [input.title, input.body, input.priority, input.dueDate, id]
  );
  if (input.tags !== undefined) {
    await db.query('DELETE FROM message_tags WHERE messageId = $1', [id]);
    await Promise.all(input.tags.map(tag =>
      db.query('INSERT INTO message_tags (messageId, tag) VALUES ($1, $2)', [id, tag])
    ));
  }
  return updated.rows[0];
}

router.put('/api/messages/:id', asyncHandler(async (req, res) => {
  const userId = req.user?.id;
  if (!userId) throw new AuthError('Unauthorized');
  const input = validateUpdateMessage(req.body);
  await fetchMessageForUpdate(req.params.id, userId);
  const message = await applyMessageUpdate(req.params.id, input);
  res.json(message);
}));
```

