  const updated = await db.query(
    'UPDATE tasks SET status = $1, status_reason = $2, status_updated_at = NOW() WHERE id = $3 RETURNING *',
    [status, reason ?? null, req.params.id]
  );
  await emitStatusEvent('task', req.params.id, status);
  res.json(updated.rows[0]);
});
