function validateTaskStatusPatch(body: unknown) {
  const { status, reason } = body as Record<string, unknown>;
  const validStatuses = ['active', 'inactive', 'pending', 'suspended'];
  if (!validStatuses.includes(status as string)) throw new ValidationError('Invalid status transition');
  if (status === 'suspended' && (!reason || (reason as string).length < 10)) throw new ValidationError('Suspension requires reason');
  return { status: status as string, reason: reason as string | undefined };
}

async function fetchTaskForStatusUpdate(id: string, userId: string, isAdmin: boolean) {
  const result = await db.query('SELECT * FROM tasks WHERE id = $1', [id]);
  if (!result.rows.length) throw new NotFoundError('Task not found');
  if (result.rows[0].user_id !== userId && !isAdmin) throw new ForbiddenError('Forbidden');
  return result.rows[0];
}

router.patch('/api/tasks/:id/status', asyncHandler(async (req, res) => {
  const userId = req.user?.id;
  if (!userId) throw new AuthError('Unauthorized');
  const patch = validateTaskStatusPatch(req.body);
  await fetchTaskForStatusUpdate(req.params.id, userId, req.user.isAdmin);
  const updated = await db.query(
    'UPDATE tasks SET status = $1, status_reason = $2, status_updated_at = NOW() WHERE id = $3 RETURNING *',
    [patch.status, patch.reason ?? null, req.params.id]
  );
  await emitStatusEvent('task', req.params.id, patch.status);
  res.json(updated.rows[0]);
}));
```

File: src/api/orderRoutes.ts
Category: route-decomposition
Instruction: Extract query parsing and database fetch logic into separate helpers. The route handler should only orchestrate.

Code to fix:
```typescript
router.get('/api/orders', async (req, res) => {
  const userId = req.user?.id;
  if (!userId) return res.status(401).json({ error: 'Unauthorized' });
  const { page, limit, sort, order, filter, search } = req.query as Record<string, string>;
  const pageNum = parseInt(page ?? '1');
  const limitNum = parseInt(limit ?? '20');
  if (isNaN(pageNum) || pageNum < 1) return res.status(400).json({ error: 'Invalid page' });
  if (isNaN(limitNum) || limitNum < 1 || limitNum > 100) return res.status(400).json({ error: 'Limit must be 1-100' });
  const validSorts = ['created_at', 'updated_at', 'name', 'status'];
  const sortCol = validSorts.includes(sort) ? sort : 'created_at';
  const sortDir = order === 'asc' ? 'ASC' : 'DESC';
  let whereClause = 'WHERE user_id = $1';
  const params: unknown[] = [userId];
  if (filter) { params.push(filter); whereClause += ` AND status = ${params.length}`; }
  if (search) { params.push(`%${search}%`); whereClause += ` AND name ILIKE ${params.length}`; }
  const countResult = await db.query(`SELECT COUNT(*) FROM orders ${whereClause}`, params);
  const total = parseInt(countResult.rows[0].count);
  const offset = (pageNum - 1) * limitNum;
  params.push(limitNum, offset);
  const result = await db.query(
    `SELECT * FROM orders ${whereClause} ORDER BY ${sortCol} ${sortDir} LIMIT ${params.length - 1} OFFSET ${params.length}`,
    params
  );
  res.json({ data: result.rows, total, page: pageNum, limit: limitNum, pages: Math.ceil(total / limitNum) });
});
```

```typescript
interface ListOrderQuery {
  page: number;
  limit: number;
  sortCol: string;
  sortDir: 'ASC' | 'DESC';
  filter?: string;
  search?: string;
}

function parseListOrderQuery(query: Record<string, string>): ListOrderQuery {
  const page = parseInt(query.page ?? '1');
  const limit = parseInt(query.limit ?? '20');
  if (isNaN(page) || page < 1) throw new ValidationError('Invalid page');
  if (isNaN(limit) || limit < 1 || limit > 100) throw new ValidationError('Limit must be 1-100');
  const validSorts = ['created_at', 'updated_at', 'name', 'status'];
  const sortCol = validSorts.includes(query.sort) ? query.sort : 'created_at';
  const sortDir = query.order === 'asc' ? 'ASC' : 'DESC';
  return { page, limit, sortCol, sortDir, filter: query.filter, search: query.search };
}

async function fetchOrderList(userId: string, q: ListOrderQuery) {
  let whereClause = 'WHERE user_id = $1';
  const params: unknown[] = [userId];
  if (q.filter) { params.push(q.filter); whereClause += ` AND status = ${params.length}`; }
  if (q.search) { params.push(`%${q.search}%`); whereClause += ` AND name ILIKE ${params.length}`; }
  const countResult = await db.query(`SELECT COUNT(*) FROM orders ${whereClause}`, params);
  const total = parseInt(countResult.rows[0].count);
  const offset = (q.page - 1) * q.limit;
  params.push(q.limit, offset);
  const result = await db.query(
    `SELECT * FROM orders ${whereClause} ORDER BY ${q.sortCol} ${q.sortDir} LIMIT ${params.length - 1} OFFSET ${params.length}`,
    params
  );
  return { data: result.rows, total, page: q.page, limit: q.limit, pages: Math.ceil(total / q.limit) };
}

router.get('/api/orders', asyncHandler(async (req, res) => {
  const userId = req.user?.id;
  if (!userId) throw new AuthError('Unauthorized');
  const query = parseListOrderQuery(req.query as Record<string, string>);
  const result = await fetchOrderList(userId, query);
  res.json(result);
}));
```

