import express from 'express';
const router = express.Router();

router.post('/api/invoices', async (req, res) => {
  const { name, email, description, status, categoryId } = req.body;
  if (!name || typeof name !== 'string' || name.trim().length === 0) {
    return res.status(400).json({ error: 'Name is required' });
  }
  if (name.length > 200) {
    return res.status(400).json({ error: 'Name too long' });
  }
  if (email && !/^[^@]+@[^@]+\.[^@]+$/.test(email)) {
    return res.status(400).json({ error: 'Invalid email format' });
  }
  if (!['active', 'inactive', 'pending'].includes(status)) {
    return res.status(400).json({ error: 'Invalid status' });
  }
  const userId = req.user?.id;
  if (!userId) return res.status(401).json({ error: 'Unauthorized' });
  const category = await db.query('SELECT id FROM categories WHERE id = $1', [categoryId]);
  if (!category.rows.length) {
    return res.status(400).json({ error: 'Category not found' });
  }
  const existing = await db.query('SELECT id FROM invoices WHERE email = $1 AND user_id = $2', [email, userId]);
  if (existing.rows.length) {
    return res.status(409).json({ error: 'Invoice already exists' });
  }
  const result = await db.query(
    'INSERT INTO invoices (user_id, name, email, description, status, category_id) VALUES ($1,$2,$3,$4,$5,$6) RETURNING *',
    [userId, name.trim(), email, description, status, categoryId]
  );
  await updateUserStats(userId);
  await notifySubscribers(userId, 'invoice.created', result.rows[0]);
