```typescript
async function getCategoryStats(userIds: string[]) {
  if (!userIds.length) return {};
  const result = await db.query(
    'SELECT user_id, COUNT(*) as cnt FROM categories WHERE user_id = ANY($1) AND status = $2 GROUP BY user_id',
    [userIds, 'active']
  );
  const stats: Record<string, number> = {};
  for (const row of result.rows) {
    stats[row.user_id] = parseInt(row.cnt);
  }
  // Fill zeros for users with no records
  for (const uid of userIds) {
    if (!(uid in stats)) stats[uid] = 0;
  }
  return stats;
}
