async function getMembershipsWithRelated(userId: string) {
  const rows = await db.query('SELECT * FROM memberships WHERE user_id = $1', [userId]);
  if (!rows.rows.length) return [];
  const ids = rows.rows.map((r: any) => r.id);
  const related = await db.query('SELECT * FROM orders WHERE membership_id = ANY($1)', [ids]);
  const relatedMap = new Map<string, any[]>();
  for (const r of related.rows) {
    const key = r.membership_id;
    if (!relatedMap.has(key)) relatedMap.set(key, []);
    relatedMap.get(key)!.push(r);
  }
  return rows.rows.map((r: any) => ({ ...r, orders: relatedMap.get(r.id) ?? [] }));
}
