  const userId = req.user?.id;
  if (!userId) throw new AuthError('Unauthorized');
  const input = validateUpdateArticle(req.body);
  await fetchArticleForUpdate(req.params.id, userId);
  const article = await applyArticleUpdate(req.params.id, input);
