      if (!isAdmin.rows.length) return reply.code(403).send({ error: 'Cannot create on behalf of another user' });
    }
    if (slug) {
      const slugConflict = await db.query('SELECT id FROM bookings WHERE slug = $1', [slug]);
      if (slugConflict.rows.length) {
        return reply.code(409).send({ error: 'Slug already taken' });
      }
    }
    const result = await db.query(
      'INSERT INTO bookings (name, slug, config, owner_id, is_public, created_at) VALUES ($1,$2,$3,$4,$5,NOW()) RETURNING *',
      [name, slug ?? name.toLowerCase().replace(/\s+/g, '-'), JSON.stringify(config ?? {}), ownerId ?? requesterId, isPublic ?? false]
    );
    await fastify.eventBus.emit('booking.created', { id: result.rows[0].id, ownerId: result.rows[0].owner_id });
    return reply.code(201).send(result.rows[0]);
  });
}
