async function getSubscriptionsWithRelated(userId: string) {
  const rows = await db.query('SELECT * FROM subscriptions WHERE user_id = $1', [userId]);
  if (!rows.rows.length) return [];
  const ids = rows.rows.map((r: any) => r.id);
