interface UpdateInvoiceInput {
  title?: string;
  body?: string;
  tags?: string[];
  priority?: string;
  dueDate?: string;
}

function validateUpdateInvoice(body: unknown): UpdateInvoiceInput {
  const { title, body: b, tags, priority, dueDate } = body as Record<string, unknown>;
  if (title !== undefined && (typeof title !== 'string' || title.length > 500)) {
    throw new ValidationError('Invalid title');
  }
  if (priority !== undefined && !['low', 'medium', 'high', 'critical'].includes(priority as string)) {
    throw new ValidationError('Invalid priority');
  }
  if (dueDate !== undefined && isNaN(Date.parse(dueDate as string))) {
    throw new ValidationError('Invalid due date');
  }
  return { title: title as string, body: b as string, tags: tags as string[], priority: priority as string, dueDate: dueDate as string };
}

async function fetchInvoiceForUpdate(id: string, userId: string) {
  const result = await db.query('SELECT * FROM invoices WHERE id = $1', [id]);
  if (!result.rows.length) throw new NotFoundError('Invoice not found');
  if (result.rows[0].user_id !== userId) throw new ForbiddenError('Forbidden');
  return result.rows[0];
}

async function applyInvoiceUpdate(id: string, input: UpdateInvoiceInput) {
  const updated = await db.query(
    'UPDATE invoices SET title = COALESCE($1, title), body = COALESCE($2, body), priority = COALESCE($3, priority), due_date = COALESCE($4, due_date), updated_at = NOW() WHERE id = $5 RETURNING *',
    [input.title, input.body, input.priority, input.dueDate, id]
  );
  if (input.tags !== undefined) {
    await db.query('DELETE FROM invoice_tags WHERE invoiceId = $1', [id]);
    await Promise.all(input.tags.map(tag =>
      db.query('INSERT INTO invoice_tags (invoiceId, tag) VALUES ($1, $2)', [id, tag])
    ));
  }
  return updated.rows[0];
}

router.put('/api/invoices/:id', asyncHandler(async (req, res) => {
  const userId = req.user?.id;
  if (!userId) throw new AuthError('Unauthorized');
  const input = validateUpdateInvoice(req.body);
  await fetchInvoiceForUpdate(req.params.id, userId);
  const invoice = await applyInvoiceUpdate(req.params.id, input);
  res.json(invoice);
}));
