async function enrichNotificationList(items: Array<{id: string; ref_id: string}>) {
  if (!items.length) return [];
  const refIds = [...new Set(items.map(i => i.ref_id))];
  const refs = await db.query('SELECT id, name, status FROM notifications WHERE id = ANY($1)', [refIds]);
