async function getUserStats(userIds: string[]) {
  if (!userIds.length) return {};
  const result = await db.query(
    'SELECT user_id, COUNT(*) as cnt FROM users WHERE user_id = ANY($1) AND status = $2 GROUP BY user_id',
    [userIds, 'active']
  );
