interface UpdateSubscriptionInput {
  title?: string;
  body?: string;
  tags?: string[];
  priority?: string;
  dueDate?: string;
}

function validateUpdateSubscription(body: unknown): UpdateSubscriptionInput {
  const { title, body: b, tags, priority, dueDate } = body as Record<string, unknown>;
  if (title !== undefined && (typeof title !== 'string' || title.length > 500)) {
    throw new ValidationError('Invalid title');
  }
  if (priority !== undefined && !['low', 'medium', 'high', 'critical'].includes(priority as string)) {
    throw new ValidationError('Invalid priority');
  }
  if (dueDate !== undefined && isNaN(Date.parse(dueDate as string))) {
    throw new ValidationError('Invalid due date');
  }
  return { title: title as string, body: b as string, tags: tags as string[], priority: priority as string, dueDate: dueDate as string };
}

async function fetchSubscriptionForUpdate(id: string, userId: string) {
  const result = await db.query('SELECT * FROM subscriptions WHERE id = $1', [id]);
  if (!result.rows.length) throw new NotFoundError('Subscription not found');
  if (result.rows[0].user_id !== userId) throw new ForbiddenError('Forbidden');
  return result.rows[0];
}

async function applySubscriptionUpdate(id: string, input: UpdateSubscriptionInput) {
  const updated = await db.query(
    'UPDATE subscriptions SET title = COALESCE($1, title), body = COALESCE($2, body), priority = COALESCE($3, priority), due_date = COALESCE($4, due_date), updated_at = NOW() WHERE id = $5 RETURNING *',
    [input.title, input.body, input.priority, input.dueDate, id]
  );
  if (input.tags !== undefined) {
    await db.query('DELETE FROM subscription_tags WHERE subscriptionId = $1', [id]);
    await Promise.all(input.tags.map(tag =>
      db.query('INSERT INTO subscription_tags (subscriptionId, tag) VALUES ($1, $2)', [id, tag])
    ));
  }
  return updated.rows[0];
}

