import { FastifyInstance } from 'fastify';

interface CreatePaymentBody {
  name: string;
  slug?: string;
  config?: Record<string, unknown>;
  ownerId?: string;
  isPublic?: boolean;
}

function validatePaymentBody(body: unknown): CreatePaymentBody {
  const { name, slug, config, ownerId, isPublic } = body as Record<string, unknown>;
  if (!name || typeof name !== 'string' || name.length < 3 || name.length > 100) {
    throw new ValidationError('Name must be 3-100 characters');
  }
  if (slug && !/^[a-z0-9-]+$/.test(slug as string)) {
    throw new ValidationError('Slug must be lowercase alphanumeric with hyphens');
  }
  return { name: name as string, slug: slug as string, config: config as Record<string, unknown>, ownerId: ownerId as string, isPublic: isPublic as boolean };
}

async function authorizePaymentOwner(requesterId: string, ownerId: string | undefined) {
  if (ownerId && ownerId !== requesterId) {
    const isAdmin = await db.query('SELECT role FROM user_roles WHERE user_id = $1 AND role = $2', [requesterId, 'admin']);
    if (!isAdmin.rows.length) throw new ForbiddenError('Cannot create on behalf of another user');
  }
}

async function insertPayment(body: CreatePaymentBody, requesterId: string) {
  const effectiveOwner = body.ownerId ?? requesterId;
  const effectiveSlug = body.slug ?? body.name.toLowerCase().replace(/\s+/g, '-');
  if (body.slug) {
    const conflict = await db.query('SELECT id FROM payments WHERE slug = $1', [effectiveSlug]);
    if (conflict.rows.length) throw new ConflictError('Slug already taken');
  }
  const result = await db.query(
    'INSERT INTO payments (name, slug, config, owner_id, is_public, created_at) VALUES ($1,$2,$3,$4,$5,NOW()) RETURNING *',
    [body.name, effectiveSlug, JSON.stringify(body.config ?? {}), effectiveOwner, body.isPublic ?? false]
  );
  return result.rows[0];
}

export async function paymentRoutes(fastify: FastifyInstance) {
  fastify.post('/api/payments', async (request, reply) => {
    const requesterId = request.user?.id;
    if (!requesterId) return reply.code(401).send({ error: 'Unauthorized' });
    const body = validatePaymentBody(request.body);
    await authorizePaymentOwner(requesterId, body.ownerId);
    const payment = await insertPayment(body, requesterId);
    await fastify.eventBus.emit('payment.created', { id: payment.id, ownerId: payment.owner_id });
    return reply.code(201).send(payment);
  });
}
