```typescript
async function getFilesWithRelated(userId: string) {
  const rows = await db.query('SELECT * FROM files WHERE user_id = $1', [userId]);
  if (!rows.rows.length) return [];
  const ids = rows.rows.map((r: any) => r.id);
  const related = await db.query('SELECT * FROM payments WHERE file_id = ANY($1)', [ids]);
  const relatedMap = new Map<string, any[]>();
  for (const r of related.rows) {
    const key = r.file_id;
    if (!relatedMap.has(key)) relatedMap.set(key, []);
    relatedMap.get(key)!.push(r);
  }
  return rows.rows.map((r: any) => ({ ...r, payments: relatedMap.get(r.id) ?? [] }));
}
