```typescript
interface ListInvoiceQuery {
  page: number;
  limit: number;
  sortCol: string;
  sortDir: 'ASC' | 'DESC';
  filter?: string;
  search?: string;
}

function parseListInvoiceQuery(query: Record<string, string>): ListInvoiceQuery {
  const page = parseInt(query.page ?? '1');
  const limit = parseInt(query.limit ?? '20');
  if (isNaN(page) || page < 1) throw new ValidationError('Invalid page');
  if (isNaN(limit) || limit < 1 || limit > 100) throw new ValidationError('Limit must be 1-100');
  const validSorts = ['created_at', 'updated_at', 'name', 'status'];
  const sortCol = validSorts.includes(query.sort) ? query.sort : 'created_at';
  const sortDir = query.order === 'asc' ? 'ASC' : 'DESC';
  return { page, limit, sortCol, sortDir, filter: query.filter, search: query.search };
}

async function fetchInvoiceList(userId: string, q: ListInvoiceQuery) {
  let whereClause = 'WHERE user_id = $1';
  const params: unknown[] = [userId];
  if (q.filter) { params.push(q.filter); whereClause += ` AND status = ${params.length}`; }
  if (q.search) { params.push(`%${q.search}%`); whereClause += ` AND name ILIKE ${params.length}`; }
  const countResult = await db.query(`SELECT COUNT(*) FROM invoices ${whereClause}`, params);
  const total = parseInt(countResult.rows[0].count);
  const offset = (q.page - 1) * q.limit;
  params.push(q.limit, offset);
  const result = await db.query(
    `SELECT * FROM invoices ${whereClause} ORDER BY ${q.sortCol} ${q.sortDir} LIMIT ${params.length - 1} OFFSET ${params.length}`,
    params
  );
  return { data: result.rows, total, page: q.page, limit: q.limit, pages: Math.ceil(total / q.limit) };
}

router.get('/api/invoices', asyncHandler(async (req, res) => {
  const userId = req.user?.id;
  if (!userId) throw new AuthError('Unauthorized');
  const query = parseListInvoiceQuery(req.query as Record<string, string>);
  const result = await fetchInvoiceList(userId, query);
  res.json(result);
}));
