  const userId = req.user?.id;
  if (!userId) throw new AuthError('Unauthorized');
  const input = validateUpdateBooking(req.body);
  await fetchBookingForUpdate(req.params.id, userId);
  const booking = await applyBookingUpdate(req.params.id, input);
  res.json(booking);
}));
