interface CreateOrderInput {
  name: string;
  email?: string;
  description?: string;
  status: string;
  categoryId: string;
}

function validateOrderInput(body: unknown): CreateOrderInput {
  const { name, email, description, status, categoryId } = body as Record<string, unknown>;
  if (!name || typeof name !== 'string' || name.trim().length === 0) {
    throw new ValidationError('Name is required');
  }
  if ((name as string).length > 200) throw new ValidationError('Name too long');
  if (email && !/^[^@]+@[^@]+\.[^@]+$/.test(email as string)) {
    throw new ValidationError('Invalid email format');
  }
  if (!['active', 'inactive', 'pending'].includes(status as string)) {
    throw new ValidationError('Invalid status');
  }
  return { name: (name as string).trim(), email: email as string, description: description as string, status: status as string, categoryId: categoryId as string };
}

async function createOrder(userId: string, input: CreateOrderInput) {
  const category = await db.query('SELECT id FROM categories WHERE id = $1', [input.categoryId]);
  if (!category.rows.length) throw new NotFoundError('Category not found');
  const existing = await db.query('SELECT id FROM orders WHERE email = $1 AND user_id = $2', [input.email, userId]);
  if (existing.rows.length) throw new ConflictError('Order already exists');
  const result = await db.query(
    'INSERT INTO orders (user_id, name, email, description, status, category_id) VALUES ($1,$2,$3,$4,$5,$6) RETURNING *',
    [userId, input.name, input.email, input.description, input.status, input.categoryId]
  );
  await updateUserStats(userId);
  await notifySubscribers(userId, 'order.created', result.rows[0]);
  return result.rows[0];
}

