```typescript
async function enrichProjectList(items: Array<{id: string; ref_id: string}>) {
  if (!items.length) return [];
  const refIds = [...new Set(items.map(i => i.ref_id))];
  const refs = await db.query('SELECT id, name, status FROM projects WHERE id = ANY($1)', [refIds]);
  const refMap = new Map(refs.rows.map((r: any) => [r.id, r]));
  return items.map(item => ({
    ...item,
    ref: refMap.get(item.ref_id) ?? null,
  }));
}
```

