      [userId, name, value ?? 0, JSON.stringify(metadata ?? {})]
    );
    await refreshCache(userId);
    res.status(201).json(row.rows[0]);
  } catch (err) {
    logger.error({ err }, 'Create notification failed');
    res.status(500).json({ error: 'Internal server error' });
  }
});
