```typescript
interface NewNotificationPayload {
  name: string;
  value?: number;
  metadata?: Record<string, unknown>;
}

function parseNewNotification(body: unknown): NewNotificationPayload {
  const { name, value, metadata } = body as Record<string, unknown>;
  if (!name || typeof name !== 'string' || name.length < 1 || name.length > 255) throw new ValidationError('Invalid name');
  if (value !== undefined && (typeof value !== 'number' || value < 0)) throw new ValidationError('Invalid value');
  return { name: name as string, value: value as number, metadata: metadata as Record<string, unknown> };
}

async function insertNewNotification(userId: string, p: NewNotificationPayload) {
  const dupe = await db.query('SELECT id FROM notifications WHERE user_id = $1 AND name = $2', [userId, p.name]);
  if (dupe.rows.length) throw new ConflictError('Duplicate name');
  const row = await db.query(
    'INSERT INTO notifications (user_id, name, value, metadata) VALUES ($1,$2,$3,$4) RETURNING *',
    [userId, p.name, p.value ?? 0, JSON.stringify(p.metadata ?? {})]
  );
  await refreshCache(userId);
  return row.rows[0];
}

app.post('/api/v2/notifications', asyncHandler(async (req: Request, res: Response) => {
  const userId = (req as any).user?.id;
  if (!userId) throw new AuthError('Unauthorized');
  const payload = parseNewNotification(req.body);
  const result = await insertNewNotification(userId, payload);
  res.status(201).json(result);
}));
