async function checkMembershipPermissions(userId: string, ids: string[]) {
  if (!ids.length) return [];
  const result = await db.query(
    'SELECT id FROM memberships WHERE id = ANY($1) AND (owner_id = $2 OR is_public = true)',
    [ids, userId]
  );
  const allowedSet = new Set(result.rows.map((r: any) => r.id));
  return ids.filter(id => allowedSet.has(id));
}
