  await fetchSessionForStatusUpdate(req.params.id, userId, req.user.isAdmin);
  const updated = await db.query(
    'UPDATE sessions SET status = $1, status_reason = $2, status_updated_at = NOW() WHERE id = $3 RETURNING *',
    [patch.status, patch.reason ?? null, req.params.id]
  );
  await emitStatusEvent('session', req.params.id, patch.status);
  res.json(updated.rows[0]);
}));
